import { defineComponentStyle } from "@yamada-ui/react"

export const textStyle = defineComponentStyle({})

export type TextStyle = typeof textStyle

import { a11y, page, render } from "#test/browser"
import { Text } from "./text"

describe("<Text />", () => {
  test("renders component correctly", async () => {
    await a11y(<Text>Text</Text>)
  })

  test("sets `displayName` correctly", () => {
    expect(Text.displayName).toBe("Text")
  })

  test("sets `className` correctly", async () => {
    await render(<Text data-testid="text">Text</Text>)
    const text = page.getByTestId("text")
    await expect.element(text).toHaveClass("ui-text")
  })

  test("renders HTML tag correctly", async () => {
    await render(<Text data-testid="text">Text</Text>)
    const text = page.getByTestId("text")
    expect(text.element().tagName).toBe("P")
  })
})

"use client"

import type { CSSProps, HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { TextStyle } from "./text.style"
import { createComponent } from "@yamada-ui/react"
import { textStyle } from "./text.style"

export interface TextProps extends HTMLStyledProps<"p">, ThemeProps<TextStyle> {
  /**
   * The CSS `text-align` property.
   */
  align?: CSSProps["textAlign"]
  /**
   * The CSS `text-transform` property.
   */
  casing?: CSSProps["textTransform"]
  /**
   * The CSS `text-decoration` property.
   */
  decoration?: CSSProps["textDecoration"]
}

const {
  PropsContext: TextPropsContext,
  usePropsContext: useTextPropsContext,
  withContext,
} = createComponent<TextProps, TextStyle>("text", textStyle)

export { TextPropsContext, useTextPropsContext }

/**
 * `Text` is a component that represents a paragraph of text. By default, it renders a `p` element.
 *
 * @see https://yamada-ui.com/docs/components/text
 */
export const Text = withContext("p")(
  undefined,
  ({
    align: textAlign,
    casing: textTransform,
    decoration: textDecoration,
    ...rest
  }) => ({
    textAlign,
    textDecoration,
    textTransform,
    ...rest,
  }),
)
